import sys
from functools import lru_cache
input = sys.stdin.readline

def solve():
    n = int(input())
    A = list(map(int, input().split()))

    @lru_cache(maxsize=None)
    def dp(l, r, last):
        # returns True if current player wins
        moves = []
        if l <= r:
            if A[l] > last:
                moves.append(dp(l+1, r, A[l]))
            if A[r] > last and r != l:
                moves.append(dp(l, r-1, A[r]))
            elif A[r] > last and r == l:
                moves.append(dp(l+1, r-1, A[r]))
        if not moves:
            return False
        return any(not m for m in moves)

    if dp(0, n-1, -1):
        print("Alice")
    else:
        print("Bob")

solve()

